import React, { useState, useEffect } from "react";
// ГЛАВНОЕ: Импорт стилей всегда должен быть в самом верху
import "./Styles/globals.scss";

import { LandingPage } from "./Pages/LandingPage/LandingPage";
import { LoginPage } from "./Pages/LoginPage/LoginPage";
import { SignupPage } from "./Pages/SignupPage/SignupPage";
import { Dashboard } from "./Pages/Dashboard/Dashboard";
import { DeadlinesPage } from "./Pages/DeadlinesPage/DeadlinesPage";
import { CoursesPage } from "./Pages/CoursesPage/CoursesPage";
import { CourseDetailsPage } from "./Pages/CourseDetailsPage/CourseDetailsPage";
import { CalendarPage } from "./Pages/CalendarPage/CalendarPage";
import { SettingsPage } from "./Pages/SettingsPage/SettingsPage";
import { Course } from "./Types/course";
import { Deadline } from "./Types/deadline";

export default function App() {
  // --- Состояния с проверкой LocalStorage ---
  const [currentPage, setCurrentPage] = useState<string>(() => {
    return localStorage.getItem("lastPage") || "landing";
  });
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem("isAuth") === "true";
  });
  const [userName, setUserName] = useState(() => {
    return localStorage.getItem("userName") || "";
  });
  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);

  const [courses, setCourses] = useState<Course[]>(() => {
    const saved = localStorage.getItem("my_courses");
    return saved ? JSON.parse(saved) : []; 
  });

  const [deadlines, setDeadlines] = useState<Deadline[]>(() => {
    const saved = localStorage.getItem("my_deadlines");
    if (saved) {
      const parsed = JSON.parse(saved);
      return parsed.map((d: any) => ({ ...d, dueDate: new Date(d.dueDate) }));
    }
    return [];
  });

  // --- Эффекты сохранения (НЕ меняют внешний вид, только пишут в память) ---
  useEffect(() => {
    localStorage.setItem("isAuth", isAuthenticated.toString());
    localStorage.setItem("lastPage", currentPage);
    localStorage.setItem("userName", userName);
  }, [isAuthenticated, currentPage, userName]);

  useEffect(() => {
    localStorage.setItem("my_courses", JSON.stringify(courses));
  }, [courses]);

  useEffect(() => {
    localStorage.setItem("my_deadlines", JSON.stringify(deadlines));
  }, [deadlines]);

  // --- Твоя оригинальная логика функций ---
  const handleLogin = (email: string, password: string) => {
    setIsAuthenticated(true);
    setCurrentPage("dashboard");
  };

  const handleSignup = (name: string, email: string, password: string) => {
    setUserName(name);
    setIsAuthenticated(true);
    setCurrentPage("dashboard");
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentPage("landing");
    localStorage.removeItem("isAuth");
    localStorage.removeItem("lastPage");
  };

  const navigateTo = (page: string) => {
    if (!isAuthenticated && !["landing", "login", "signup"].includes(page)) {
      setCurrentPage("login");
      return;
    }
    setCurrentPage(page);
  };

  const viewCourseDetails = (courseId: string) => {
    setSelectedCourseId(courseId);
    setCurrentPage("course-details");
  };

  const addDeadline = (deadline: Omit<Deadline, "id">) => {
    const newDeadline = { ...deadline, id: Date.now().toString() };
    setDeadlines([...deadlines, newDeadline as Deadline]);
  };

  const updateDeadline = (id: string, updatedDeadline: Partial<Deadline>) => {
    setDeadlines(deadlines.map((d) => (d.id === id ? { ...d, ...updatedDeadline } : d)));
  };

  const deleteDeadline = (id: string) => {
    setDeadlines(deadlines.filter((d) => d.id !== id));
  };

  const addCourse = (course: Omit<Course, "id">) => {
    const newCourse = { ...course, id: Date.now().toString() };
    setCourses([...courses, newCourse]);
  };

  const updateUserName = (name: string) => {
    setUserName(name);
  };

  // --- Твой оригинальный рендеринг ---
  const renderPage = () => {
    if (!isAuthenticated) {
      switch (currentPage) {
        case "login": return <LoginPage onLogin={handleLogin} onNavigate={navigateTo} />;
        case "signup": return <SignupPage onSignup={handleSignup} onNavigate={navigateTo} />;
        default: return <LandingPage onNavigate={navigateTo} />;
      }
    }

    switch (currentPage) {
      case "dashboard":
        return <Dashboard userName={userName} deadlines={deadlines} courses={courses} onNavigate={navigateTo} onLogout={handleLogout} onAddDeadline={addDeadline as any} onUpdateDeadline={updateDeadline} />;
      case "deadlines":
        return <DeadlinesPage deadlines={deadlines} courses={courses} onNavigate={navigateTo} onLogout={handleLogout} onAddDeadline={addDeadline as any} onUpdateDeadline={updateDeadline} onDeleteDeadline={deleteDeadline} />;
      case "courses":
        return <CoursesPage courses={courses} deadlines={deadlines} onNavigate={navigateTo} onLogout={handleLogout} onViewCourse={viewCourseDetails} onAddCourse={addCourse} />;
      case "course-details":
        const selectedCourse = courses.find((c) => c.id === selectedCourseId);
        return selectedCourse ? (
          <CourseDetailsPage course={selectedCourse} deadlines={deadlines.filter((d) => d.courseId === selectedCourseId)} onNavigate={navigateTo} onLogout={handleLogout} onAddDeadline={addDeadline as any} onBack={() => navigateTo("courses")} />
        ) : null;
      case "calendar":
        return <CalendarPage deadlines={deadlines} courses={courses} onNavigate={navigateTo} onLogout={handleLogout} onAddDeadline={addDeadline as any} />;
      case "settings":
        return <SettingsPage userName={userName} onNavigate={navigateTo} onLogout={handleLogout} onUpdateName={updateUserName} />;
      default:
        return <Dashboard userName={userName} deadlines={deadlines} courses={courses} onNavigate={navigateTo} onLogout={handleLogout} onAddDeadline={addDeadline as any} onUpdateDeadline={updateDeadline} />;
    }
  };

  return <div className="app">{renderPage()}</div>;
}
